const batchItems = $("Batch SKU Collector").all();
let useCache = false;
let productMap = {};

try {
    const binaryData = $node["Read Cache File"].binary?.data;
    if (binaryData) {
        const jsonContent = Buffer.from(binaryData.data, 'base64').toString('utf8');
        const simplifiedProducts = JSON.parse(jsonContent);

        simplifiedProducts.forEach(p => {
            productMap[p.fields.Product_Name] = p.fields.Total_Base_Cost;
        });

        const missingSkus = batchItems.filter(item => productMap[item.json.Search_SKU] === undefined);

        if (missingSkus.length === 0) {
            useCache = true;
            batchItems.forEach(item => {
                item.json.Total_Base_Cost = productMap[item.json.Search_SKU] || 0;
                item.json.Base_Cost_Source = 'Cache';
            });
        }
    }
} catch (e) {
    useCache = false;
}

return batchItems.map(item => ({
    json: { ...item.json, useCache: useCache }
}));

